INSERT INTO `knowledge_base` VALUES (1,_binary '','NETWORK','2026-01-28 15:51:45.117029',_binary '\0','VPN Connection Issues - Updated','VPN_CONNECTION','vpn, connection, failed, timeout',1,'Step 1: Restart VPN client\nStep 2: Check internet\nStep 3: Reconnect',0,0,'2026-01-28 15:55:38.941225',0),(2,_binary '','NETWORK','2026-01-29 04:05:23.959333',_binary '','WiFi Connection Issues','WIFI','wifi, wireless, network, connection, internet, not connecting',1,'1. Restart your laptop\n2. Forget and reconnect to WiFi\n3. Run: ipconfig /release then ipconfig /renew\n4. Restart router if needed',1,0.5,'2026-03-26 09:45:32.315296',2),(3,_binary '','NETWORK','2026-02-01 12:26:34.000000',_binary '','VPN Connection Issues','VPN','vpn,cisco,anyconnect,connection,connect,disconnect,timeout',10,'[\"Disconnect from any existing VPN connection\", \"Restart the Cisco AnyConnect client\", \"Clear your browser cache and cookies\", \"Check if your internet connection is working properly\", \"Try connecting to a different VPN server if available\", \"Restart your computer and try again\", \"If still not working, check if VPN credentials need to be updated\"]',5,0.45454545454545453,'2026-03-29 12:23:54.749802',12),(4,_binary '','NETWORK','2026-02-01 12:26:34.000000',_binary '','WiFi/Wireless Connection Issues','WIFI','wifi,wireless,wifi,signal,disconnect,slow,network',9,'[\"Check if WiFi is enabled on your device\", \"Toggle WiFi off and on again\", \"Forget the current network and reconnect with credentials\", \"Move closer to the WiFi router/access point\", \"Restart your computer/device\", \"Check if other devices can connect to the same network\", \"Reset network settings: Settings ??? Network ??? Reset\"]',4,0.5,'2026-04-01 14:09:13.626715',11),(5,_binary '','NETWORK','2026-02-01 12:26:34.000000',_binary '','Internet Access Issues','INTERNET','internet,browsing,web,access,slow,connection',8,'[\"Check if your network cable is properly connected (for LAN)\", \"Open Command Prompt and run: ipconfig /release then ipconfig /renew\", \"Try accessing different websites to confirm if issue is general\", \"Clear DNS cache: Open CMD as Admin and run: ipconfig /flushdns\", \"Check if proxy settings are correct in browser\", \"Restart your router/modem if possible\", \"Contact IT if issue persists across all devices\"]',0,0.75,'2026-02-26 14:30:00.320533',2),(6,_binary '','NETWORK','2026-02-01 12:26:34.000000',_binary '','LAN/Ethernet Connection Issues','LAN','lan,ethernet,cable,wired,port,network,adapter',7,'[\"Check if the ethernet cable is properly connected at both ends\", \"Try a different ethernet port on your device or wall socket\", \"Check for any visible damage on the cable\", \"Disable and re-enable the network adapter: Control Panel ??? Network ??? Change adapter settings\", \"Update network drivers: Device Manager ??? Network adapters ??? Update driver\", \"Try a different ethernet cable if available\"]',1,1,'2026-04-01 16:39:36.971023',6),(7,_binary '','ACCESS','2026-02-01 12:26:34.000000',_binary '','Password Reset','PASSWORD','password,reset,forgot,change,expired,unlock',10,'[\"Go to the Password Reset Portal: https://passwordreset.powergrid.in\", \"Click on Forgot Password or Reset Password\", \"Enter your Employee ID and registered email/mobile\", \"You will receive an OTP on your registered contact\", \"Enter the OTP and set a new password\", \"Password requirements: Minimum 8 characters, 1 uppercase, 1 number, 1 special character\", \"Wait 5 minutes before trying to login with new password\"]',2,0.5,'2026-03-31 15:24:28.744184',4),(8,_binary '','ACCESS','2026-02-01 12:26:34.000000',_binary '','Account Unlock','ACCOUNT_UNLOCK','locked,unlock,account,lockout,blocked,login,failed',9,'[\"Wait 30 minutes - accounts auto-unlock after lockout period\", \"If urgent, go to Self-Service Portal: https://selfservice.powergrid.in\", \"Select Account Unlock option\", \"Verify your identity using security questions or OTP\", \"Your account will be unlocked immediately\", \"Ensure CAPS LOCK is off before entering password\", \"If still locked, contact IT Helpdesk\"]',0,0.9,'2026-02-01 12:26:34.000000',0),(9,_binary '\0','ACCESS','2026-02-01 12:26:34.000000',_binary '','Access Permission Request','PERMISSION','permission,access,folder,share,drive,restricted',5,'[\"This request requires manager approval\", \"Please fill the Access Request Form on ServiceNow portal\", \"Select the resource/folder/application you need access to\", \"Provide business justification for the access\", \"Submit the request - it will be routed to your manager\", \"Once approved, access will be granted within 24 hours\", \"You will receive email confirmation when access is granted\"]',0,0,'2026-02-01 12:26:34.000000',0),(10,_binary '','SOFTWARE','2026-02-01 12:26:34.000000',_binary '','Application Login Issues','LOGIN','login,signin,authentication,credentials,access,failed',9,'[\"Clear browser cache and cookies: Ctrl+Shift+Delete\", \"Try logging in using Incognito/Private mode\", \"Ensure you are using the correct username format (e.g., employee@powergrid.in)\", \"Check if CAPS LOCK is enabled\", \"Try resetting your password using the Forgot Password option\", \"Disable any browser extensions that might interfere\", \"Try a different browser (Chrome, Edge, Firefox)\"]',1,0.3333333333333333,'2026-04-01 15:15:05.352721',3),(11,_binary '','SOFTWARE','2026-02-01 12:26:34.000000',_binary '','Application Crash/Freeze','CRASH','crash,freeze,hang,stuck,not responding,error,stopped',8,'[\"Force close the application: Ctrl+Alt+Delete ??? Task Manager ??? End Task\", \"Restart your computer\", \"Check for application updates and install if available\", \"Run the application as Administrator: Right-click ??? Run as Administrator\", \"Clear application cache/temporary files\", \"Check if there is enough disk space (at least 10% free)\", \"Try repairing the installation from Control Panel ??? Programs\"]',0,0.72,'2026-02-01 12:26:34.000000',0),(12,_binary '\0','SOFTWARE','2026-02-01 12:26:34.000000',_binary '','Software Installation Request','INSTALLATION','install,setup,software,application,program,download',5,'[\"Check if the software is available in Company Software Center\", \"Open Software Center from Start Menu\", \"Search for the required software\", \"Click Install and wait for completion\", \"If not available in Software Center, raise a request on ServiceNow\", \"Provide business justification for the software\", \"Note: Installation of unauthorized software is not permitted\"]',0,0,'2026-02-01 12:26:34.000000',0),(13,_binary '','SOFTWARE','2026-02-01 12:26:34.000000',_binary '','Software Update Issues','UPDATE','update,upgrade,patch,version,outdated',7,'[\"Restart your computer to complete pending updates\", \"Check Windows Update: Settings ??? Update & Security ??? Windows Update\", \"For specific software, check Help ??? Check for Updates\", \"Ensure you have stable internet connection during update\", \"If update fails, try running Windows Update Troubleshooter\", \"Clear Windows Update cache: Stop wuauserv service, delete C:\\Windows\\SoftwareDistribution, restart service\", \"Contact IT if critical security updates are failing\"]',0,0.7,'2026-03-29 10:07:53.349854',3),(14,_binary '','SOFTWARE','2026-02-01 12:26:34.000000',_binary '','Application/System Performance Issues','PERFORMANCE','slow,performance,speed,lag,sluggish,freeze,memory',8,'[\"Close unnecessary applications and browser tabs\", \"Check Task Manager for high CPU/Memory usage: Ctrl+Shift+Esc\", \"End any processes using excessive resources\", \"Restart your computer to clear memory\", \"Run Disk Cleanup: Search for Disk Cleanup in Start Menu\", \"Disable startup programs: Task Manager ??? Startup tab\", \"Check for malware: Run Windows Defender scan\", \"Ensure at least 20% disk space is free\"]',0,0.75,'2026-02-01 12:26:34.000000',0),(15,_binary '','EMAIL','2026-02-01 12:26:34.000000',_binary '','Outlook Application Issues','OUTLOOK','outlook,email,client,crash,freeze,slow,not opening',9,'[\"Close Outlook completely\", \"Start Outlook in Safe Mode: Hold Ctrl while clicking Outlook icon\", \"If Safe Mode works, disable add-ins: File ??? Options ??? Add-ins ??? Manage COM Add-ins\", \"Repair Outlook: Control Panel ??? Programs ??? Microsoft Office ??? Change ??? Repair\", \"Delete and recreate Outlook profile: Control Panel ??? Mail ??? Show Profiles\", \"Check if OST file is too large (>50GB): Archive old emails\", \"Run SCANPST.exe to repair OST/PST files\"]',0,0.8,'2026-02-01 12:26:34.000000',0),(16,_binary '','EMAIL','2026-02-01 12:26:34.000000',_binary '','Cannot Send Emails','EMAIL_SEND','send,sending,email,outbox,stuck,failed,delivery',8,'[\"Check your internet connection\", \"Verify the recipient email address is correct\", \"Check if your Outbox has stuck emails - try resending\", \"Reduce attachment size (limit: 25MB for external)\", \"Check if you are not exceeding daily send limit\", \"Try sending from Outlook Web Access (OWA)\", \"Check if your account is not blocked: Contact IT if sending to external domains fails\"]',0,0.75,'2026-02-01 12:26:34.000000',0),(17,_binary '','EMAIL','2026-02-01 12:26:34.000000',_binary '','Cannot Receive Emails','EMAIL_RECEIVE','receive,receiving,inbox,missing,email,not getting',8,'[\"Check your Junk/Spam folder for missing emails\", \"Verify your mailbox is not full: Check quota in Outlook\", \"Click Send/Receive All Folders button\", \"Check if rules are moving emails to other folders\", \"Verify the sender is not blocked: Settings ??? Mail ??? Blocked Senders\", \"Try accessing email via Outlook Web Access\", \"Ask sender to resend with different subject line\"]',0,0.7,'2026-02-01 12:26:34.000000',0),(18,_binary '','EMAIL','2026-02-01 12:26:34.000000',_binary '','Calendar/Meeting Issues','CALENDAR','calendar,meeting,invite,schedule,appointment,room,booking',7,'[\"Refresh your calendar: F5 or Send/Receive\", \"Check if you have the correct time zone: File ??? Options ??? Calendar\", \"For meeting not showing: Ask organizer to resend invite\", \"Clear calendar cache: Close Outlook, delete content from %localappdata%\\Microsoft\\Outlook\\\", \"Check shared calendar permissions with the owner\", \"For recurring meeting issues: Delete and recreate the series\", \"Try accessing calendar via Outlook Web Access\"]',0,0.72,'2026-02-01 12:26:34.000000',0),(19,_binary '','HARDWARE','2026-02-01 12:26:34.000000',_binary '','Printer Issues','PRINTER','printer,print,printing,paper,jam,queue,offline',8,'[\"Check if printer is powered on and not showing errors\", \"Verify printer has paper and ink/toner\", \"Check cable connection (USB) or network connectivity\", \"Set as default printer: Settings ??? Devices ??? Printers\", \"Clear print queue: Services ??? Print Spooler ??? Stop ??? Delete files in C:\\Windows\\System32\\spool\\PRINTERS ??? Start\", \"Remove and re-add the printer\", \"Update printer driver from manufacturer website\"]',0,0.75,'2026-04-01 13:43:44.636832',2),(20,_binary '','HARDWARE','2026-02-01 12:26:34.000000',_binary '','Monitor/Display Issues','MONITOR','monitor,display,screen,blank,black,flickering,resolution',8,'[\"Check if monitor is powered on\", \"Verify cable connections (HDMI/VGA/DisplayPort)\", \"Try a different cable if available\", \"Adjust resolution: Right-click Desktop ??? Display Settings\", \"Update display drivers: Device Manager ??? Display adapters\", \"Connect to a different port on the laptop/PC\", \"Test monitor with a different device to isolate issue\", \"For external monitor not detected: Windows+P ??? Extend/Duplicate\"]',0,0.7,'2026-02-01 12:26:34.000000',0),(21,_binary '','HARDWARE','2026-02-01 12:26:34.000000',_binary '','Keyboard Issues','KEYBOARD','keyboard,keys,typing,not working,stuck,layout',7,'[\"Check if keyboard is properly connected\", \"Try a different USB port\", \"Check if Num Lock/Caps Lock is affecting input\", \"Restart your computer\", \"Check keyboard language: Windows+Space to switch\", \"Update keyboard driver: Device Manager ??? Keyboards\", \"Test with On-Screen Keyboard: Start ??? On-Screen Keyboard\", \"For laptop: Check if Fn key is stuck or pressed\"]',1,1,'2026-04-02 17:23:18.028041',3),(22,_binary '','HARDWARE','2026-02-01 12:26:34.000000',_binary '','Mouse Issues','MOUSE','mouse,cursor,pointer,click,scroll,not moving,wireless',7,'[\"Check if mouse is properly connected\", \"Try a different USB port\", \"For wireless mouse: Replace batteries or check Bluetooth connection\", \"Clean the mouse sensor and mouse pad\", \"Update mouse driver: Device Manager ??? Mice and other pointing devices\", \"Adjust mouse settings: Settings ??? Devices ??? Mouse\", \"Test with a different mouse to isolate the issue\"]',0,0.82,'2026-02-01 12:26:34.000000',0),(23,_binary '','HARDWARE','2026-02-01 12:26:34.000000',_binary '','Laptop Issues','LAPTOP','laptop,notebook,boot,power,battery,charge,start',8,'[\"For boot issues: Hold power button for 10 seconds, then restart\", \"Check battery charge level\", \"Connect power adapter and verify charging LED\", \"Remove all external devices and try booting\", \"Try booting in Safe Mode: Hold Shift and click Restart\", \"Check for overheating: Ensure vents are not blocked\", \"For screen issues: Connect external monitor to test\", \"Hard reset: Power off, remove battery if possible, hold power 30 sec, reconnect and start\"]',0,0.65,'2026-04-01 14:49:03.634836',3);
